.component-scale-description {
  font-family: 'Montserrat', sans-serif;
  font-size: 19px;
  font-weight: 400;
  color: #262626;
  margin-bottom: 1rem;
  line-height: 1.6;
}

.component-level-title {
  font-family: 'Montserrat', sans-serif;
  font-size: 25px;
  font-weight: 600;
  color: #1f2937;
  margin-bottom: 0.75rem;
}

.component-level-highlight {
  color: #347aec;
  font-weight: 700;
}

.component-level-text {
  font-family: 'Montserrat', sans-serif;
  font-size: 18px;
  font-weight: 400;
  color: #1f2937;
  line-height: 1.6;
  margin: 0;
}

@media (max-width: 1280px) {
  .emotional-intelligence-page {
    max-width: 100%;
    width: 100%;
    margin: 0 auto;
  }

  .emotional-intelligence-main {
    padding: 1.5rem;
    margin-left: 0;
  }

  .emotional-intelligence-content {
    padding: 1.5rem;
  }

  .answer-options-grid {
    gap: 0.75rem;
  }

  .answer-options-grid > .answer-option-button:nth-child(4n-1),
  .answer-options-grid > .answer-option-button:nth-child(4n) {
    margin-left: -133px;
  }

  .answer-options-grid > .answer-option-button.answer-option-number:nth-child(4n) {
    margin-left: calc(-98px + 78px);
  }

  .questions-content {
    flex-direction: column;
  }

  .questions-numbers {
    margin-left: 0;
    justify-content: flex-start;
  }

  .question-item {
    width: 100%;
  }

  .progress-block {
    margin-left: 370px;
    margin-top: 0;
  }

  .result-button-section {
    margin-left: -140px;
  }

  .test-navigation {
    margin-left: -140px;
    justify-content: center;
  }

  .navigation-buttons {
    margin-left: 0;
  }
}

/* Адаптация для экранов 480px и меньше */
@media screen and (max-width: 480px) {
  html,
  body {
    overflow-x: hidden !important;
    width: 100% !important;
    max-width: 100vw !important;
  }

  .emotional-intelligence-page {
    min-height: 100vh !important;
    background-color: #f3f4f6 !important;
    display: flex !important;
    flex-direction: column !important;
    max-width: 100vw !important;
    width: 100% !important;
    margin: 0 !important;
    padding: 0 !important;
    padding-bottom: 80px !important;
  }

  .emotional-intelligence-main {
    padding: 1.25rem !important; /* Немного уменьшенный общий padding */
    padding-top: calc(
      1.25rem + 80px
    ) !important; /* Отступ от хедера 80px (было 100px, подняли еще на 20px) */
    padding-bottom: 4rem !important;
    width: 100% !important;
    max-width: 100% !important;
    margin-top: 0 !important; /* Убираем отрицательный margin-top */
    margin-left: 0 !important; /* Сдвигаем всё содержимое вправо на 10px (было -10px, теперь 0px) */
  }

  .emotional-intelligence-content,
  .emotional-intelligence-section,
  .emotional-intelligence-question-card,
  .emotional-intelligence-summary,
  .emotional-intelligence-results,
  .emotional-intelligence-result-card {
    margin-top: -20px !important;
  }

  .emotional-intelligence-content {
    max-width: 100% !important;
    width: 100% !important;
    margin: 0 !important;
    padding: 1rem !important;
    box-sizing: border-box !important;
  }

  .emotional-intelligence-title {
    font-size: 22px !important;
    margin-bottom: 0.75rem !important;
    line-height: 1.2 !important;
  }

  .emotional-intelligence-description {
    font-size: 16px !important;
    margin-bottom: 1.5rem !important;
    line-height: 1.5 !important;
  }

  .emotional-intelligence-instructions {
    flex-direction: column !important;
    align-items: center !important;
    gap: 1rem !important;
    margin-bottom: 1.5rem !important;
  }

  .instructions-bubble {
    width: 100% !important;
    max-width: 100% !important;
    height: auto !important;
    min-height: 100px !important;
  }

  .instructions-content {
    padding: 1rem 1.5rem !important;
    margin-top: -10px !important;
  }

  .instructions-text {
    font-size: 16px !important;
    margin: 0.25rem 0 !important;
    line-height: 1.4 !important;
  }

  .instructions-robot {
    display: none !important;
  }

  .robot-image {
    width: 150px !important;
    height: auto !important;
    max-height: 200px !important;
  }

  .answer-options-title {
    font-size: 30px !important;
    margin-bottom: 1rem !important;
    margin-top: 0 !important;
  }

  .answer-options-grid {
    grid-template-columns: minmax(0, 1fr) 56px !important;
    column-gap: 0.75rem !important;
    row-gap: 0.75rem !important;
    margin-bottom: 1.5rem !important;
  }

  .answer-option-button {
    width: 100% !important;
    max-width: 100% !important;
    height: auto !important;
    min-height: 54px !important;
    padding: 0.9rem 1rem !important;
    border-radius: 12px !important;
    box-shadow: 0 10px 22px rgba(31, 41, 55, 0.08) !important;
  }

  .answer-option-button:not(.answer-option-number) {
    width: 100% !important;
    height: auto !important;
    min-height: 54px !important;
    padding: 0.9rem 1rem !important;
    display: flex !important;
    justify-content: flex-start !important;
    align-items: center !important;
  }

  .answer-option-button.answer-option-number {
    width: 56px !important;
    height: 54px !important;
    min-height: 54px !important;
    padding: 0 !important;
    margin-left: 0 !important;
    justify-content: center !important;
  }

  .answer-options-grid > .answer-option-button:nth-child(4n-1),
  .answer-options-grid > .answer-option-button:nth-child(4n) {
    margin-left: 0 !important;
  }

  .answer-options-grid > .answer-option-button.answer-option-number:nth-child(4n) {
    margin-left: 0 !important;
  }

  .answer-option-label {
    font-size: 16px !important;
